def build_circuit() -> QuantumCircuit:
    qc = QuantumCircuit(2, 1)
    qc.h(0)
    qc.measure(0, 0)
    qc.reset(0)
    with qc.if_test((0, 1)):
            qc.x(1)
    return qc


